  Rpc.make('config.tenant', {
    error: ConfigHeaderRpcError,
    payload: Schema.Void,
    success: Tenant,
  }),
);

export class ConfigRpcs extends RpcGroup.make(
  ConfigPublic,
  ConfigIsAuthenticated,
  ConfigPermissionList,
  ConfigTenant,
) {}

