@Injectable({
  providedIn: 'root',
})
export class ConfigService {
  public get missingContext() {
    return this._missingContext;
  }

  public get permissions(): Permission[] {
    return this._permissions;
  }

  public get publicConfig() {
    return this._publicConfig;
  }

